import Mathlib.Init.Data.Nat.Basic
import Mathlib.Init.Data.Nat.Int
import Mathlib.Init.Data.List.Basic
import Mathlib.Init.Data.Option.Basic
import Init.Datatypes
open Nat
open List
open Option

inductive CStruct.nethost (a : Type) : Type where
| empty
| { addr : IP.address a, addrs : list IP.address a, xmit : int, returned : int, sent : int, up : bool, var : int64, last : int, best : int, worst : int, avg : real, gmean : real, jitter : int, javg : int, jworst : int, jinta : int, transit : int, saved : list int, saved_seq_offset : int }

inductive IP.address (a : Type) : Type where
| ipv4 : Nat -> IP.address a
| ipv6 : IPv6.address a

inductive IPv6.address (a : Type) : Type where
| inet : String -> IPv6.address a

inductive IP.protocol : Type where
| ip { version : Nat, tos : Nat, len : Nat, id : Nat, frag : Nat, ttl : Nat, protocol : Nat, check : Nat, saddr : IP.address IPv4.address, daddr : IP.address IPv4.address }
| icmp { type : Nat, code : Nat, checksum : Nat, id : Nat, sequence : Nat }

def IP.protocol.ipv4 : IP.protocol := 
{ version := 4, tos := 0, len := 0, id := 0, frag := 0, ttl := 0, protocol := IPPROTO_IP, check := 0, saddr := IPv4.address.ipv4 0, daddr := IPv4.address.ipv4 0 }

def IP.protocol.icmp : IP.protocol := 
{ version := 4, tos := 0, len := 0, id := 0, frag := 0, ttl := 0, protocol := IPPROTO_ICMP, check := 0, saddr := IPv4.address.ipv4 0, daddr := IPv4.address.ipv4 0 }

def IPv4.address.ipv4 (ip : Nat) : IP.address IPv4.address :=
{ IP.address.ipv4.val := ip }

def IP.address.ipv4 (ip : Nat) : IP.address :=
{ IP.address.ipv4 }

def IPv6.address.inet (ip : String) : IPv6.address IPv4.address :=
{ IPv6.address.inet.val := ip }

def IP.address.ipv6 (ip : IPv6.address IPv4.address) : IP.address :=
{ IP.address.ipv6 }
