import Mathlib.Tactic.Classic
open Lean.Elab.Tactics
open Lean.Syntax
open Lean.Core.Syntax

-- Define functions and types for C code translation
inductive CFunction : Type :=
| CFunctionExtern { name : Name, argTypes : List Type, body : Option Expr }

inductive CExpr : Type :=
| CExprInt { value : Int }
| CExprVar { name : Name }
| CExprFunctionCall { func : CFunction, args : List CExpr }
| CExprError
| CExprAssign { lhs : CExpr, rhs : CExpr }
| CExprIf { cond : CExpr, thenBranch : CExpr, elseBranch : Option CExpr }
| CExprWhile { cond : CExpr, body : CExpr }

def CProgram : Type :=
{ name : Name
, functions : List CFunction
, globalVariables : List Name
, entryPoint : Name
}

def init (p : CProgram) : Expr :=
match p with
| { name := n, functions := l, globalVariables := g, entryPoint := e } =>
do let ⟨entryFn⟩ ← find (λ f, f.name = e) l
let body ← getFnBody entryFn
return `(do
  let mut n := var Int.zero
  { n := n.succ }
  let _ ← `(if (n < 3) do return) <| `(CExprInt 3) <| body
  unreachable)

def getFnBody (cf : CFunction) : Option Expr :=
match cf with
| CFunctionExtern { name := n, argTypes, body := some b } => some b
| _ => none

