lean_proof_s123:
 ===BEGIN LEAN PROOF===
import Mathlib.Tactic.Classical
open Nat

/- Definition of the rec function in Lean 4 -/
def rec (a : Nat) : Nat :=
if a = 0 then 0
else (let res := rec (a - 1) in
 let rescopy := res in
 let i := nat.succ (pred rescopy) in
 i + 1)

/- Property to prove: LTL (F end) in the context of the given main function -/
lemma ltl_end : LTL (fun _ : State Nat => λ _, F fun _ => false) (init (main) fun _ => rec)
| proof
  have : ∀ i : Nat, i ≤ 0 → rec i = 0 :=
    induction i with i IH
    | { d := 0; apply IH _ _ }
    | { d := succ i; simp only [rec] using ← nat.succ_sub,
        intros h_le; simp [h_le, nat.succ_zero] }

  have : ∀ i : Nat, i > 0 → rec i > 0 :=
    induction i with i IH
    | { d := 0; apply false }
    | { d := succ i; simp only [rec] using ← nat.succ_pred,
        intros h_gt; apply IH h_gt }

  have : ∀ i : Nat, i > 0 → rec i ≥ 1 :=
    induction i with i IH
    | { d := 0; apply false }
    | { d := succ i; simp only [rec, IH, succ_succ] }

  have : ∀ i : Nat, i > 0 → F (rec i) :=
    induction i with i IH
    | { d := 0; apply false }
    | { d := succ i; simp only [rec, IH, nat.succ_gt_zero, F] }

  apply classical.contrapose (λ h, LTL.ne_true_iff_forall_eventually.mpr h)
  intros i h_le
  cases h_le with h_le h_le'
  { apply ltl_end.have h_le }
  { apply ltl_end.have h_le' }

  intros i h_gt
  cases h_gt with h_gt h_gt'
  { apply ltl_end.have h_gt }
  { apply ltl_end.have h_gt' }

  intros i h_gt
  cases h_gt with h_gt h_gt'
  { apply ltl_end.have h_gt }
  { simp only [ltl_end.have h_gt', F, nat.succ_ge, h_gt, nat.succ_gt] }

  intros i h_gt
  cases h_gt with h_gt h_gt'
  { apply ltl_end.have h_gt }
  { simp only [ltl_end.have h_gt', F, lt_succ_ge_iff, h_gt, nat.succ_gt] }

  apply classical.contrapose (λ h, ∃ i, i > 0 ∧ F (rec i))
  intros i h_i h_gt h_f
  apply ltl_end.have h_gt
  exact h_f
===END LEAN PROOF===

