import Mathlib.Tactic
import Mathlib.Int.Basic

open Nat
open List

variables {a : Array Int 1048}

definition ranking_function (k : Nat) : Int := 1048 - k

lemma init_main : init (fun () => do {
  let a := Array.fill 1048 (-1)
  let mut k : Nat := 0
  while k < 1048 ∧ a.get k ≥ 0 do
    if (rand) then do
      a.set k 0
      k := k + 1
    else do
      a.set k (a.get k - 1)
  k
}) = some 1048

lemma G_def_behavior : ∀ n, ∀ (xs : List Int), ∀ i, i < Array.length a → a.get i = xs.get (i - ranking_function i) ∨ a.get i < 0
| n xs i => by {
  induction n with d hn; intros; assumption;
  simp only [hn, ranking_function];
  cases a.get i <| by simp;
  cases a.get i <| by simp [h: Array.get_spec a, hn];
  simp only [h];
  intro hk;
  simp only [hk, h: Array.get_spec a, hn];
  rw [← Array.length_cons, ← Array.get_spec];
  exact xs.get (i + d - ranking_function (i + d))
}
