 ===BEGIN LEAN PROOF===
import Mathlib.Core.Algebra.Order.Basic
import Mathlib.Tactics.Core

open Nat Int

def bool : Type := { false | true }

def c_program (): Int := do {
  let bob : Int := 13
  let samantha : Int := 17
  let mut temp : Int := 0

  while bob + samantha < 100 do
  begin
    temp := bob
    bob := samantha
    samantha := temp
  end

  return 0
}

@[speculate]
lemma init_main : init c_program () = some 0

lemma while_loop_condition (bob samantha : Int) : bob + samantha < 100 → bob < samantha → samantha < temp → temp < bob := by {
  intros h_condition h_bob h_samantha h_temp
  simp [h_condition, h_bob, h_samantha, h_temp] at*
  exact le_trans _ h_samantha
}

lemma while_loop_preserves_condition (bob samantha temp : Int) (h_condition : bob + samantha < 100) :
  (temp < bob) → (bob + samantha = temp + samantha) → (bob + samantha < 100) := by {
  intros h_temp h_preserves_condition
  simp [h_preserves_condition, h_condition] at*
  exact le_trans _ h_samantha
}

lemma while_loop_termination (bob samantha : Int) (h_condition : bob + samantha < 100) :
  ∃ temp, temp < bob := by {
  have h_temp_exists : ∃ temp, temp < bob := by {
    intro h_temp_lt_bob
    rcases h_temp_lt_bob with ⟨t, h_temp, h_lt_bob⟩
    have h_temp_is_bob : temp = bob := by {
      simp [h_lt_bob]
    }
    exact (h_temp_is_bob, h_temp)
  }
  have h_temp_lt_bob : temp < bob := h_temp_exists.1
  have h_condition_with_temp : bob + samantha + temp < 100 := by {
    calc bob + samantha + temp = (bob + samantha) + temp
    ... < 100 by [h_condition, h_temp_lt_bob, le_add, le_refl]
  }
  have h_no_more_swaps : ∀ k : Nat, (k < (Nat.min bob samantha)) → (bob < samantha) → samantha < temp → temp < bob → bob + samantha < 100 := by {
    intros k h_k h_bob_lt_sam h_sam_lt_temp h_temp_lt_bob h_condition'
    have h_temp : temp = samantha := by {
      simp [h_k, h_sam_lt_temp]
    }
    simp [h_temp, h_bob_lt_sam, h_temp_lt_bob, h_condition', h_condition] at*
    exact h_condition'
  }
  contradiction
    have h_termination : ∀ k, (bob < samantha) → samantha < temp → temp < bob → bob + samantha < 100 := by {
      intros k h_bob_lt_sam h_sam_lt_temp h_temp_lt_bob
      have h_temp : temp = bob := by {
        simp [h_k, h_temp_lt_bob]
      }
      simp [h_temp, h_bob_lt_sam, h_sam_lt_temp] at*
      exact h_condition
    }
    have h_no_swap : ∃ k, ∀ i, (i < k) → (bob < samantha) → samantha < temp → temp < bob → bob + samantha < 100 := by {
      intros h_no_swap_i
      induction i with i iih
      { simp [h_no_swap_i.1, h_bob_lt_sam, h_sam_lt_temp] at* }
      { simp [h_no_swap_i.2, h_bob_lt_sam, h_sam_lt_temp, h_termination i] }
    }
    have h_swap : bob < samantha := h_no_swap.1.1
    have h_final_condition : bob + samantha < 100 := h_no_swap.1.2
    exact h_final_condition
  }
}

theorem c_program_LTL_F_end : LTL (F (fun _ => 100)) (c_program ()) := by {
  have init_main_some_zero := init_main.get_or_else (fun h => contradiction)
  simp [init_main_some_zero] at*
  induction i using (finset.induction _) (fun h_i h => h.2)
  { intros h_i
    simp [h_i] at*
    exact h_i.1
  }
  { simp [h_i] at*
    exact h_i.2
  }
  have h_init : init (c_program ()) = some 0 := init_main
  simp [h_init] at*
  simp [h_i]
  have h_swap : bob < samantha := h_i.1
  have h_temp : temp < bob := h_i.2
  have h_condition : bob + samantha < 100 := while_loop_termination h_swap h_temp
  simp [h_condition] at*
  exact le_trans _ (le_add _ (le_refl 0))
}
===END LEAN PROOF===

