import Mathlib

open nat list function

def rand (): nat := by do { let n := 2147483647 in sample ≤ n }

def init_array (a : array nat nat) (n : nat) : array nat nat :=
  let i := 0 in
  if h : n > 0 then do {
    for i in 0..n-1 do a[i] ← i + 1 + i
  } else error "Array size cannot be zero"
  a

def modify_array_1 (a : array nat nat) (n : nat) : array nat nat :=
  let i := 0 in
  if h : n > 0 then do {
    for i in 0..n-1 do a[i] ← a[i] - (i * i)
  } else error "Array size cannot be zero"
  a

def modify_array_2 (a : array nat nat) (n : nat) : array nat nat :=
  let i := 0 in
  if h : n > 0 then do {
    for i in 0..n-1 do a[i] ← a[i] - i
  } else error "Array size cannot be zero"
  a

